select set_config('request.jwt.claim.role','authenticated',true),set_config('request.jwt.claim.sub','71000000-0000-0000-0000-000000000005',true);

-- Seed stock through the public Phase One opening workflow.  The physical
-- source entry and its external-control counterpart are posted atomically;
-- inventory_apply_projection is therefore the only writer of the projection.
select id as opening_base_unit from public.inventory_item_units where inventory_item_profile_id='71000000-0000-0000-0000-000000000007' and is_base_unit and active \gset
select public.create_inventory_opening_command(
  '71000000-0000-0000-0000-000000000001',
  '71000000-0000-0000-0000-000000000002',
  '71000000-0000-0000-0000-000000000003',
  'opening',
  jsonb_build_array(
    jsonb_build_object('profile_id','71000000-0000-0000-0000-000000000007','batch_id','71000000-0000-0000-0000-000000000012','unit_id',:'opening_base_unit','channel','system','account_type','physical','location_id','71000000-0000-0000-0000-000000000009','disposition','available','quantity_base',20),
    jsonb_build_object('profile_id','71000000-0000-0000-0000-000000000007','batch_id','71000000-0000-0000-0000-000000000012','unit_id',:'opening_base_unit','channel','system','account_type','external_control','quantity_base',-20),
    jsonb_build_object('profile_id','71000000-0000-0000-0000-000000000007','batch_id','71000000-0000-0000-0000-000000000025','unit_id',:'opening_base_unit','channel','system','account_type','physical','location_id','71000000-0000-0000-0000-000000000009','disposition','available','quantity_base',12),
    jsonb_build_object('profile_id','71000000-0000-0000-0000-000000000007','batch_id','71000000-0000-0000-0000-000000000025','unit_id',:'opening_base_unit','channel','system','account_type','external_control','quantity_base',-12),
    jsonb_build_object('profile_id','71000000-0000-0000-0000-000000000007','batch_id','71000000-0000-0000-0000-000000000025','unit_id',:'opening_base_unit','channel','legacy_off_system','account_type','physical','location_id','71000000-0000-0000-0000-000000000009','disposition','available','quantity_base',7),
    jsonb_build_object('profile_id','71000000-0000-0000-0000-000000000007','batch_id','71000000-0000-0000-0000-000000000025','unit_id',:'opening_base_unit','channel','legacy_off_system','account_type','external_control','quantity_base',-7)
  ),
  'transfer-opening-1','transfer-opening-hash-0001','transfer test opening'
) as opening_command \gset
select public.submit_inventory_command(:'opening_command');

reset role;
set local role authenticated;
select set_config('request.jwt.claim.role','authenticated',true),set_config('request.jwt.claim.sub','71000000-0000-0000-0000-000000000026',true);
select public.approve_inventory_command(:'opening_command') as opening_transaction \gset

reset role;
select public.transfer_test_assert(coalesce((select status='posted' and result_transaction_id=:'opening_transaction'::uuid from public.inventory_commands where id=:'opening_command'::uuid),false),'opening command is posted with its transaction');
select public.transfer_test_assert((select count(*)=1 from public.inventory_transactions where id=:'opening_transaction'::uuid),'one opening transaction exists');
select public.transfer_test_assert(
  exists(select 1 from public.inventory_ledger_entries where transaction_id=:'opening_transaction'::uuid)
  and not exists(
    select 1
    from (
      select sum(quantity_base) as balance
      from public.inventory_ledger_entries
      where transaction_id=:'opening_transaction'::uuid
      group by inventory_item_profile_id,batch_id,recording_channel,inventory_item_unit_id
    ) balanced
    where balanced.balance <> 0
  ),
  'opening ledger is balanced by item batch channel and unit'
);
select public.transfer_test_assert(coalesce((select coalesce(sum(quantity_base),0)=20 from public.inventory_ledger_entries where transaction_id=:'opening_transaction'::uuid and account_type='physical' and location_id='71000000-0000-0000-0000-000000000009' and inventory_item_profile_id='71000000-0000-0000-0000-000000000007' and batch_id='71000000-0000-0000-0000-000000000012' and recording_channel='system' and inventory_item_unit_id=:'opening_base_unit'::uuid and disposition='available'),false),'opening source ledger equals intended quantity');
select public.transfer_test_assert(coalesce((select quantity_base=20 from public.inventory_balance_projections where location_id='71000000-0000-0000-0000-000000000009' and inventory_item_profile_id='71000000-0000-0000-0000-000000000007' and batch_id='71000000-0000-0000-0000-000000000012' and recording_channel='system' and disposition='available'),false),'opening source projection equals intended quantity');
select public.transfer_test_assert(not exists(
  select 1
  from public.inventory_balance_projections bp
  where bp.location_id='71000000-0000-0000-0000-000000000009'
    and bp.inventory_item_profile_id='71000000-0000-0000-0000-000000000007'
    and bp.batch_id='71000000-0000-0000-0000-000000000012'
    and bp.recording_channel='system'
    and bp.disposition='available'
    and bp.quantity_base is distinct from (
      select coalesce(sum(le.quantity_base),0)
      from public.inventory_ledger_entries le
      where le.account_type='physical'
        and le.location_id=bp.location_id
        and le.inventory_item_profile_id=bp.inventory_item_profile_id
        and le.batch_id=bp.batch_id
        and le.recording_channel=bp.recording_channel
        and le.disposition=bp.disposition
    )
),'opening source ledger and projection reconcile');
select public.transfer_test_assert((select count(*)=1 from public.inventory_commands where id=:'opening_command'::uuid) and (select count(*)=1 from public.inventory_transactions where command_id=:'opening_command'::uuid),'opening command has no duplicate effect');

