-- A test-only audit failure must roll back the claimed closure command and all
-- of its dependent effects before the remaining valid allocation closure.
create function public.transfer_test_fail_closure_audit() returns trigger language plpgsql as $$ begin if current_setting('app.test_fail_transfer_audit',true)='on' and new.action='inventory.transfer_remainder_closed' then raise exception 'test closure audit failure'; end if; return new; end $$;
create trigger transfer_test_fail_closure_audit before insert on public.audit_events for each row execute function public.transfer_test_fail_closure_audit();
select count(*) as closure_fixture_commands_before_audit_failure from public.inventory_commands where requester_id='71000000-0000-0000-0000-000000000005' and idempotency_key='closure-fixture-audit-failure' \gset
set local role authenticated;
select set_config('request.jwt.claim.role','authenticated',true),set_config('request.jwt.claim.sub','71000000-0000-0000-0000-000000000005',true),set_config('app.test_fail_transfer_audit','on',true);
select public.transfer_test_expect_failure($$select public.close_inventory_transfer_remainder('71000000-0000-0000-0000-000000000021','[{"transfer_line_id":"71000000-0000-0000-0000-000000000022","transfer_allocation_id":"71000000-0000-0000-0000-000000000023","inventory_item_profile_id":"71000000-0000-0000-0000-000000000007","quantity_base":1}]'::jsonb,'closure-fixture-audit-failure','forced audit failure')$$,'test closure audit failure');
select set_config('app.test_fail_transfer_audit','off',true);
reset role;
select public.transfer_test_assert((select count(*) from public.inventory_commands where requester_id='71000000-0000-0000-0000-000000000005' and idempotency_key='closure-fixture-audit-failure')=:'closure_fixture_commands_before_audit_failure'::int and (select count(*) from public.inventory_transfer_remainder_closures where transfer_id='71000000-0000-0000-0000-000000000021')=1 and (select count(*) from public.inventory_transfer_events where transfer_id='71000000-0000-0000-0000-000000000021' and action='inventory.transfer_remainder_closed')=1 and (select count(*) from public.audit_events where entity_type='inventory_transfer' and entity_id='71000000-0000-0000-0000-000000000021' and action='inventory.transfer_remainder_closed')=1,'forced audit failure rolls back closure command and effects');
drop trigger transfer_test_fail_closure_audit on public.audit_events;
drop function public.transfer_test_fail_closure_audit();

