select public.transfer_test_assert(exists(select 1 from pg_trigger t join pg_proc p on p.oid=t.tgfoid where t.tgrelid='public.inventory_transfer_remainder_closures'::regclass and t.tgenabled<>'D' and t.tgname='inventory_transfer_remainder_closure_immutable' and p.proname='prevent_inventory_transfer_remainder_closure_mutation'),'closure table has an enabled append-only update/delete trigger');

set local role authenticated;
