-- Database-only uniqueness and relational probes.  The savepoint makes the
-- valid first inserts disposable and proves constraints independently of RPC.
reset role;
savepoint closure_direct_database_probes;
do $$
declare cmd_line uuid:='71000000-0000-0000-0000-000000000041'; cmd_alloc uuid:='71000000-0000-0000-0000-000000000042'; cmd_bad uuid:='71000000-0000-0000-0000-000000000043'; other_profile uuid:='71000000-0000-0000-0000-000000000044'; other_line uuid:='71000000-0000-0000-0000-000000000045'; other_alloc uuid:='71000000-0000-0000-0000-000000000046'; other_reservation uuid:='71000000-0000-0000-0000-000000000047'; other_transfer uuid:='71000000-0000-0000-0000-000000000048'; other_transfer_line uuid:='71000000-0000-0000-0000-000000000049'; other_transfer_alloc uuid:='71000000-0000-0000-0000-000000000050'; begin
 insert into public.catalog_items(id,item_name_en,created_by,updated_by) values('71000000-0000-0000-0000-000000000040','Probe item','71000000-0000-0000-0000-000000000005','71000000-0000-0000-0000-000000000005');
 insert into public.inventory_item_profiles(id,tenant_id,organization_id,facility_id,catalog_item_id,active,created_by,updated_by) values(other_profile,'71000000-0000-0000-0000-000000000001','71000000-0000-0000-0000-000000000002','71000000-0000-0000-0000-000000000003','71000000-0000-0000-0000-000000000040',false,'71000000-0000-0000-0000-000000000005','71000000-0000-0000-0000-000000000005');
