 insert into public.inventory_transfer_remainder_closures(transfer_id,transfer_line_id,inventory_item_profile_id,quantity_base,command_id,reason,created_by) values('71000000-0000-0000-0000-000000000021','71000000-0000-0000-0000-000000000022','71000000-0000-0000-0000-000000000007',1,cmd_line,'probe','71000000-0000-0000-0000-000000000005');
 begin insert into public.inventory_transfer_remainder_closures(transfer_id,transfer_line_id,inventory_item_profile_id,quantity_base,command_id,reason,created_by) values('71000000-0000-0000-0000-000000000021','71000000-0000-0000-0000-000000000022','71000000-0000-0000-0000-000000000007',1,cmd_line,'probe','71000000-0000-0000-0000-000000000005'); raise exception 'line uniqueness probe did not fail'; exception when unique_violation then null; end;
 insert into public.inventory_transfer_remainder_closures(transfer_id,transfer_line_id,transfer_allocation_id,inventory_item_profile_id,reservation_id,quantity_base,command_id,reason,created_by) select '71000000-0000-0000-0000-000000000021','71000000-0000-0000-0000-000000000022','71000000-0000-0000-0000-000000000023','71000000-0000-0000-0000-000000000007',id,1,cmd_alloc,'probe','71000000-0000-0000-0000-000000000005' from public.inventory_reservations where transfer_allocation_id='71000000-0000-0000-0000-000000000023';
 begin insert into public.inventory_transfer_remainder_closures(transfer_id,transfer_line_id,transfer_allocation_id,inventory_item_profile_id,quantity_base,command_id,reason,created_by) values('71000000-0000-0000-0000-000000000021','71000000-0000-0000-0000-000000000022','71000000-0000-0000-0000-000000000023','71000000-0000-0000-0000-000000000007',1,cmd_alloc,'probe','71000000-0000-0000-0000-000000000005'); raise exception 'allocation uniqueness probe did not fail'; exception when unique_violation then null; end;
 insert into public.inventory_transfer_lines(id,transfer_id,inventory_item_profile_id,requested_quantity_base,created_by) values(other_line,'71000000-0000-0000-0000-000000000021',other_profile,1,'71000000-0000-0000-0000-000000000005');
 insert into public.inventory_transfer_allocations(id,transfer_line_id,source_location_id,batch_id,recording_channel,planned_quantity_base,created_by) values(other_alloc,other_line,'71000000-0000-0000-0000-000000000009','71000000-0000-0000-0000-000000000025','system',1,'71000000-0000-0000-0000-000000000005');
 insert into public.inventory_reservations(id,transfer_allocation_id,quantity_base,expires_at,created_by) values(other_reservation,other_alloc,1,now()+interval '1 hour','71000000-0000-0000-0000-000000000005');
 insert into public.inventory_transfers(id,tenant_id,organization_id,facility_id,source_location_id,destination_root_location_id,transit_location_id,created_by,updated_by) select other_transfer,tenant_id,organization_id,facility_id,source_location_id,destination_root_location_id,transit_location_id,'71000000-0000-0000-0000-000000000005','71000000-0000-0000-0000-000000000005' from public.inventory_transfers where id='71000000-0000-0000-0000-000000000021';
 insert into public.inventory_transfer_lines(id,transfer_id,inventory_item_profile_id,requested_quantity_base,created_by) values(other_transfer_line,other_transfer,'71000000-0000-0000-0000-000000000007',1,'71000000-0000-0000-0000-000000000005');
 insert into public.inventory_transfer_allocations(id,transfer_line_id,source_location_id,batch_id,recording_channel,planned_quantity_base,created_by) values(other_transfer_alloc,other_transfer_line,'71000000-0000-0000-0000-000000000009','71000000-0000-0000-0000-000000000025','system',1,'71000000-0000-0000-0000-000000000005');
 begin insert into public.inventory_transfer_remainder_closures(transfer_id,transfer_line_id,inventory_item_profile_id,quantity_base,command_id,reason,created_by) values(other_transfer,'71000000-0000-0000-0000-000000000022','71000000-0000-0000-0000-000000000007',1,cmd_bad,'probe','71000000-0000-0000-0000-000000000005'); raise exception 'transfer mismatch did not fail'; exception when others then if position('line integrity denied' in sqlerrm)=0 then raise; end if; end;
 begin insert into public.inventory_transfer_remainder_closures(transfer_id,transfer_line_id,inventory_item_profile_id,quantity_base,command_id,reason,created_by) values('71000000-0000-0000-0000-000000000021','71000000-0000-0000-0000-000000000022',other_profile,1,cmd_bad,'probe','71000000-0000-0000-0000-000000000005'); raise exception 'profile mismatch did not fail'; exception when others then if position('line integrity denied' in sqlerrm)=0 then raise; end if; end;
 begin insert into public.inventory_transfer_remainder_closures(transfer_id,transfer_line_id,transfer_allocation_id,inventory_item_profile_id,quantity_base,command_id,reason,created_by) values('71000000-0000-0000-0000-000000000021','71000000-0000-0000-0000-000000000022',other_alloc,'71000000-0000-0000-0000-000000000007',1,cmd_bad,'probe','71000000-0000-0000-0000-000000000005'); raise exception 'other line allocation did not fail'; exception when others then if position('allocation integrity denied' in sqlerrm)=0 then raise; end if; end;
 begin insert into public.inventory_transfer_remainder_closures(transfer_id,transfer_line_id,transfer_allocation_id,inventory_item_profile_id,quantity_base,command_id,reason,created_by) values('71000000-0000-0000-0000-000000000021','71000000-0000-0000-0000-000000000022',other_transfer_alloc,'71000000-0000-0000-0000-000000000007',1,cmd_bad,'probe','71000000-0000-0000-0000-000000000005'); raise exception 'other transfer allocation did not fail'; exception when others then if position('allocation integrity denied' in sqlerrm)=0 then raise; end if; end;
 begin insert into public.inventory_transfer_remainder_closures(transfer_id,transfer_line_id,transfer_allocation_id,inventory_item_profile_id,reservation_id,quantity_base,command_id,reason,created_by) values('71000000-0000-0000-0000-000000000021','71000000-0000-0000-0000-000000000022','71000000-0000-0000-0000-000000000023','71000000-0000-0000-0000-000000000007',other_reservation,1,cmd_bad,'probe','71000000-0000-0000-0000-000000000005'); raise exception 'reservation mismatch did not fail'; exception when others then if position('reservation integrity denied' in sqlerrm)=0 then raise; end if; end;
 begin insert into public.inventory_transfer_remainder_closures(transfer_id,transfer_line_id,inventory_item_profile_id,reservation_id,quantity_base,command_id,reason,created_by) values('71000000-0000-0000-0000-000000000021','71000000-0000-0000-0000-000000000022','71000000-0000-0000-0000-000000000007',other_reservation,1,cmd_bad,'probe','71000000-0000-0000-0000-000000000005'); raise exception 'unallocated reservation did not fail'; exception when check_violation then null; end;
 begin insert into public.inventory_transfer_remainder_closures(transfer_id,transfer_line_id,inventory_item_profile_id,quantity_base,command_id,reason,created_by) values('71000000-0000-0000-0000-000000000021','71000000-0000-0000-0000-000000000022','71000000-0000-0000-0000-000000000007',0,cmd_bad,'probe','71000000-0000-0000-0000-000000000005'); raise exception 'zero did not fail'; exception when check_violation then null; end;
 begin insert into public.inventory_transfer_remainder_closures(transfer_id,transfer_line_id,inventory_item_profile_id,quantity_base,command_id,reason,created_by) values('71000000-0000-0000-0000-000000000021','71000000-0000-0000-0000-000000000022','71000000-0000-0000-0000-000000000007',-1,cmd_bad,'probe','71000000-0000-0000-0000-000000000005'); raise exception 'negative did not fail'; exception when check_violation then null; end;
 begin insert into public.inventory_transfer_remainder_closures(transfer_id,transfer_line_id,inventory_item_profile_id,quantity_base,command_id,reason,created_by) values('71000000-0000-0000-0000-000000000021','71000000-0000-0000-0000-000000000022','71000000-0000-0000-0000-000000000007',1,cmd_bad,'','71000000-0000-0000-0000-000000000005'); raise exception 'empty reason did not fail'; exception when check_violation then null; end;
 begin insert into public.inventory_transfer_remainder_closures(transfer_id,transfer_line_id,inventory_item_profile_id,quantity_base,command_id,reason,created_by) values('71000000-0000-0000-0000-000000000021','71000000-0000-0000-0000-000000000022','71000000-0000-0000-0000-000000000007',1,cmd_bad,'   ','71000000-0000-0000-0000-000000000005'); raise exception 'whitespace reason did not fail'; exception when check_violation then null; end;
 perform set_config('app.inventory_transfer_controlled','off',true); set constraints all immediate;
end $$;
rollback to savepoint closure_direct_database_probes;

-- The final receipt resolves the only remaining physical transit quantity;
-- demand was already closed, so the existing cached-state model completes.
select public.receive_inventory_transfer('71000000-0000-0000-0000-000000000021',jsonb_build_array(jsonb_build_object('transfer_allocation_id','71000000-0000-0000-0000-000000000023','quantity_base',3,'destination_location_id','71000000-0000-0000-0000-000000000011','destination_disposition','available')),'closure-fixture-receive-1','closure-fixture-receive-hash-0001','resolve closure fixture transit');
reset role;
select public.transfer_test_assert(coalesce((select transit_quantity_base=0 and returns_hold_quantity_base=0 and issued_quantity_base+closed_remainder_quantity_base=requested_quantity_base from public.inventory_transfer_summary_projection where transfer_line_id='71000000-0000-0000-0000-000000000022'),false) and coalesce((select status='completed' from public.inventory_transfers where id='71000000-0000-0000-0000-000000000021'),false),'resolved closure fixture reaches completed state');

set local role authenticated;
select set_config('request.jwt.claim.role','authenticated',true),set_config('request.jwt.claim.sub','71000000-0000-0000-0000-000000000005',true);
select public.reserve_inventory_transfer(:'transfer_id',now()+interval '1 hour','transfer-reserve-1','transfer-reserve-hash-0001');
select public.transfer_test_assert((select status='reserved' from public.inventory_transfers where id=:'transfer_id'),'reservation derives reserved status');
select public.issue_inventory_transfer(:'transfer_id',jsonb_build_array(jsonb_build_object('transfer_allocation_id',:'allocation_id','quantity_base',6)),'transfer-issue-1','transfer-issue-hash-0001','partial issue') as issued_transfer \gset
select public.issue_inventory_transfer(:'transfer_id',jsonb_build_array(jsonb_build_object('transfer_allocation_id',:'allocation_id','quantity_base',6)),'transfer-issue-1','transfer-issue-hash-0001','partial issue') as issue_replay \gset
select public.transfer_test_assert(:'issued_transfer'::uuid=:'issue_replay'::uuid,'issue replay returns same transfer');
select public.transfer_test_assert((select quantity_base=14 from public.inventory_balance_projections where location_id='71000000-0000-0000-0000-000000000009' and batch_id='71000000-0000-0000-0000-000000000012' and disposition='available'),'issue decreases source');
select public.transfer_test_expect_failure(format('select public.issue_inventory_transfer(%L::uuid,jsonb_build_array(jsonb_build_object(''transfer_allocation_id'',%L,''quantity_base'',5)),''transfer-issue-over'',''transfer-issue-over-hash'',''over'')',:'transfer_id',:'allocation_id'),'Inventory transfer issue exceeds reservation remaining quantity');

-- Reject is a ledger reclassification, then return consumes only returns_hold.
select public.reject_inventory_transfer(:'transfer_id',jsonb_build_array(jsonb_build_object('transfer_allocation_id',:'allocation_id','quantity_base',2)),'transfer-reject-1','transfer-reject-hash-0001','damaged on arrival');
select public.transfer_test_assert((select quantity_base=4 from public.inventory_balance_projections where location_id=(select transit_location_id from public.inventory_transfers where id=:'transfer_id') and batch_id='71000000-0000-0000-0000-000000000012' and disposition='transit') and (select quantity_base=2 from public.inventory_balance_projections where location_id=(select transit_location_id from public.inventory_transfers where id=:'transfer_id') and batch_id='71000000-0000-0000-0000-000000000012' and disposition='returns_hold'),'reject reclassifies transit to returns hold');
select public.return_rejected_inventory_transfer(:'transfer_id',jsonb_build_array(jsonb_build_object('transfer_allocation_id',:'allocation_id','quantity_base',1)),'transfer-return-1','transfer-return-hash-0001','return one');
select public.receive_inventory_transfer(:'transfer_id',jsonb_build_array(jsonb_build_object('transfer_allocation_id',:'allocation_id','quantity_base',4,'destination_location_id','71000000-0000-0000-0000-000000000011','destination_disposition','available')),'transfer-receive-1','transfer-receive-hash-0001','receive into child');
select public.transfer_test_assert((select count(*)=1 from public.inventory_transfer_receipt_destinations rd join public.inventory_transfer_operations op on op.id=rd.operation_id where op.transfer_id=:'transfer_id' and rd.quantity_base=op.quantity_base),'receipt child preserves operation grain and quantity');
select public.return_rejected_inventory_transfer(:'transfer_id',jsonb_build_array(jsonb_build_object('transfer_allocation_id',:'allocation_id','quantity_base',1)),'transfer-return-2','transfer-return-hash-0001','return remaining');
select public.close_inventory_transfer_remainder(:'transfer_id',jsonb_build_array(jsonb_build_object('transfer_line_id',(select id from public.inventory_transfer_lines where transfer_id=:'transfer_id'),'transfer_allocation_id',:'allocation_id','inventory_item_profile_id','71000000-0000-0000-0000-000000000007','quantity_base',4)),'transfer-close-1','close unissued remainder');
reset role;
select public.transfer_test_assert((select status='completed' from public.inventory_transfers where id=:'transfer_id'),'controlled status matches derived completion');
select public.transfer_test_assert((select count(*)=0 from public.inventory_transfer_operations where transfer_id=:'transfer_id' and transfer_allocation_id is null and operation_type not in ('close_remainder','cancel')),'physical operations require allocation linkage');
select public.transfer_test_assert((select count(*)>0 from public.audit_events where entity_type='inventory_transfer' and entity_id=:'transfer_id'),'transfer events write shared audit');

-- Reservation adjustments are the only accounting source.  The main issue is
-- partial, its replay is already exercised above, and the cross-allocation
-- fixture provides a second independently posted issue adjustment.
select public.transfer_test_assert(
  (select count(*)=1 from public.inventory_reservation_adjustments ra join public.inventory_transfer_operations o on o.id=ra.related_operation_id where o.transfer_id=:'transfer_id' and o.command_id=(select id from public.inventory_commands where idempotency_key='transfer-issue-1') and ra.adjustment_type='issue_consumed' and ra.quantity_base=6)
  and (select count(*)=2 from public.inventory_reservation_adjustments ra join public.inventory_transfer_operations o on o.id=ra.related_operation_id where o.transfer_id='71000000-0000-0000-0000-000000000061' and ra.adjustment_type='issue_consumed')
  and not exists(select 1 from public.inventory_reservations r where public.inventory_transfer_reservation_remaining(r.id) is distinct from r.quantity_base-coalesce((select sum(ra.quantity_base) from public.inventory_reservation_adjustments ra where ra.reservation_id=r.id),0)),
  'partial and multiple issues create one issue adjustment per operation and remaining equals reservation minus adjustments'
);
set local role authenticated;
select set_config('request.jwt.claim.role','authenticated',true),set_config('request.jwt.claim.sub','71000000-0000-0000-0000-000000000005',true);
select public.transfer_test_expect_failure($$select public.issue_inventory_transfer('71000000-0000-0000-0000-000000000061','[{"transfer_allocation_id":"71000000-0000-0000-0000-000000000064","quantity_base":2}]'::jsonb,'line-bound-issue-b-3-1','different-line-bound-issue-hash','different replay request')$$,'Inventory idempotency key was reused with a different request');
reset role;
select public.transfer_test_assert((select count(*)=1 from public.inventory_reservation_adjustments ra join public.inventory_transfer_operations o on o.id=ra.related_operation_id join public.inventory_commands c on c.id=o.command_id where c.idempotency_key='line-bound-issue-b-3-1' and ra.adjustment_type='issue_consumed'),'issue replay and changed-key rejection do not duplicate adjustments');

-- A controlled audit failure after the ledger and operation inserts rolls back
-- the command, physical posting, operation and its issue_consumed adjustment.
create function public.transfer_test_fail_adjustment_issue_event() returns trigger language plpgsql as $$ begin if current_setting('app.transfer_adjustment_test_fail',true)='on' and new.transfer_id='71000000-0000-0000-0000-000000000074' and new.action='inventory.transfer_issued' then raise exception 'forced reservation adjustment audit failure'; end if; return new; end $$;
create trigger transfer_test_adjustment_issue_audit_failure before insert on public.inventory_transfer_events for each row execute function public.transfer_test_fail_adjustment_issue_event();
select (select count(*) from public.inventory_commands where requester_id='71000000-0000-0000-0000-000000000005' and idempotency_key='adjustment-forced-issue-1') as commands,(select count(*) from public.inventory_transfer_operations where transfer_id='71000000-0000-0000-0000-000000000074' and operation_type='issue') as operations,(select count(*) from public.inventory_reservation_adjustments ra join public.inventory_reservations r on r.id=ra.reservation_id where r.transfer_allocation_id='71000000-0000-0000-0000-000000000076') as adjustments,(select count(*) from public.inventory_ledger_entries where batch_id='71000000-0000-0000-0000-000000000077') as ledger,(select coalesce(sum(quantity_base),0) from public.inventory_balance_projections where location_id='71000000-0000-0000-0000-000000000009' and batch_id='71000000-0000-0000-0000-000000000077' and recording_channel='system' and disposition='available') as source_qty,(select coalesce(sum(quantity_base),0) from public.inventory_balance_projections where location_id=(select transit_location_id from public.inventory_transfers where id='71000000-0000-0000-0000-000000000074') and batch_id='71000000-0000-0000-0000-000000000077' and recording_channel='system' and disposition='transit') as transit_qty \gset adjustment_forced_before_
set local role authenticated;
select set_config('request.jwt.claim.role','authenticated',true),set_config('request.jwt.claim.sub','71000000-0000-0000-0000-000000000005',true),set_config('app.transfer_adjustment_test_fail','on',true);
select public.transfer_test_expect_failure($$select public.issue_inventory_transfer('71000000-0000-0000-0000-000000000074','[{"transfer_allocation_id":"71000000-0000-0000-0000-000000000076","quantity_base":1}]'::jsonb,'adjustment-forced-issue-1','adjustment-forced-issue-hash-0001','force audit rollback')$$,'forced reservation adjustment audit failure');
select set_config('app.transfer_adjustment_test_fail','off',true);
reset role;
select public.transfer_test_assert((select count(*) from public.inventory_commands where requester_id='71000000-0000-0000-0000-000000000005' and idempotency_key='adjustment-forced-issue-1')=:'adjustment_forced_before_commands'::int and (select count(*) from public.inventory_transfer_operations where transfer_id='71000000-0000-0000-0000-000000000074' and operation_type='issue')=:'adjustment_forced_before_operations'::int and (select count(*) from public.inventory_reservation_adjustments ra join public.inventory_reservations r on r.id=ra.reservation_id where r.transfer_allocation_id='71000000-0000-0000-0000-000000000076')=:'adjustment_forced_before_adjustments'::int and (select count(*) from public.inventory_ledger_entries where batch_id='71000000-0000-0000-0000-000000000077')=:'adjustment_forced_before_ledger'::int and (select coalesce(sum(quantity_base),0) from public.inventory_balance_projections where location_id='71000000-0000-0000-0000-000000000009' and batch_id='71000000-0000-0000-0000-000000000077' and recording_channel='system' and disposition='available')=:'adjustment_forced_before_source_qty'::numeric and (select coalesce(sum(quantity_base),0) from public.inventory_balance_projections where location_id=(select transit_location_id from public.inventory_transfers where id='71000000-0000-0000-0000-000000000074') and batch_id='71000000-0000-0000-0000-000000000077' and recording_channel='system' and disposition='transit')=:'adjustment_forced_before_transit_qty'::numeric,'forced audit failure rolls back issue command, adjustment, operation and physical posting');
drop trigger transfer_test_adjustment_issue_audit_failure on public.inventory_transfer_events;
drop function public.transfer_test_fail_adjustment_issue_event();

-- Cancellation releases only the reservation amount still derived as
-- remaining.  It creates no physical ledger/projection movement or legacy
-- reservation-event accounting row.
select (select count(*) from public.inventory_ledger_entries where batch_id='71000000-0000-0000-0000-000000000077') as ledger,(select count(*) from public.inventory_balance_projections where batch_id='71000000-0000-0000-0000-000000000077') as projections,(select count(*) from public.inventory_reservation_events re join public.inventory_reservations r on r.id=re.reservation_id where r.transfer_allocation_id='71000000-0000-0000-0000-000000000076') as legacy_events \gset adjustment_cancel_before_
set local role authenticated;
select set_config('request.jwt.claim.role','authenticated',true),set_config('request.jwt.claim.sub','71000000-0000-0000-0000-000000000005',true);
select public.cancel_inventory_transfer('71000000-0000-0000-0000-000000000074','adjustment-cancel-1','adjustment-cancel-hash-0001','release reserved remainder');
reset role;
select public.transfer_test_assert((select count(*)=1 from public.inventory_reservation_adjustments ra join public.inventory_reservations r on r.id=ra.reservation_id where r.transfer_allocation_id='71000000-0000-0000-0000-000000000076' and ra.adjustment_type='manually_released' and ra.quantity_base=4) and (select public.inventory_transfer_reservation_remaining(r.id)=0 from public.inventory_reservations r where r.transfer_allocation_id='71000000-0000-0000-0000-000000000076') and (select count(*) from public.inventory_ledger_entries where batch_id='71000000-0000-0000-0000-000000000077')=:'adjustment_cancel_before_ledger'::int and (select count(*) from public.inventory_balance_projections where batch_id='71000000-0000-0000-0000-000000000077')=:'adjustment_cancel_before_projections'::int and (select count(*) from public.inventory_reservation_events re join public.inventory_reservations r on r.id=re.reservation_id where r.transfer_allocation_id='71000000-0000-0000-0000-000000000076')=:'adjustment_cancel_before_legacy_events'::int,'cancellation releases exact remaining through adjustments without physical or legacy-event accounting effects');

-- Allocation closures release an exact reservation amount; line-unallocated
-- closures intentionally have no reservation linkage or adjustment.
select public.transfer_test_assert(
  exists(select 1 from public.inventory_reservation_adjustments ra join public.inventory_transfer_remainder_closures c on c.id=ra.related_closure_id where c.transfer_id='71000000-0000-0000-0000-000000000087' and ra.adjustment_type='closure_released' and ra.quantity_base=2)
  and not exists(select 1 from public.inventory_transfer_remainder_closures c left join public.inventory_reservation_adjustments ra on ra.related_closure_id=c.id where c.transfer_id='71000000-0000-0000-0000-000000000021' and c.transfer_allocation_id is null and ra.id is not null)
  and not exists(select 1 from public.inventory_reservations r where public.inventory_transfer_reservation_remaining(r.id)<0),
  'allocation closure releases its reservation exactly while line-unallocated closure creates no adjustment'
);

-- Trusted probes exercise the table protections independently of the public
-- functions.  All are rolled back after the expected failure.
savepoint reservation_adjustment_direct_probes;
do $$
declare cmd_cancel uuid:='71000000-0000-0000-0000-000000000097'; cmd_issue uuid:='71000000-0000-0000-0000-000000000098'; cmd_close uuid:='71000000-0000-0000-0000-000000000099'; res_a uuid; res_b uuid; op_a uuid; close_other uuid; begin
  select id into res_a from public.inventory_reservations where transfer_allocation_id='71000000-0000-0000-0000-000000000063';
  select id into res_b from public.inventory_reservations where transfer_allocation_id='71000000-0000-0000-0000-000000000064';
  select id into op_a from public.inventory_transfer_operations where transfer_allocation_id='71000000-0000-0000-0000-000000000063' and operation_type='issue' limit 1;
  select id into close_other from public.inventory_transfer_remainder_closures where transfer_id='71000000-0000-0000-0000-000000000087' limit 1;
  insert into public.inventory_commands(id,tenant_id,organization_id,facility_id,command_type,requester_id,approver_id,idempotency_key,request_hash,payload) values
    (cmd_cancel,'71000000-0000-0000-0000-000000000001','71000000-0000-0000-0000-000000000002','71000000-0000-0000-0000-000000000003','transfer_cancel','71000000-0000-0000-0000-000000000005','71000000-0000-0000-0000-000000000005','adjustment-probe-cancel','adjustment-probe-cancel-hash','{}'),
    (cmd_issue,'71000000-0000-0000-0000-000000000001','71000000-0000-0000-0000-000000000002','71000000-0000-0000-0000-000000000003','transfer_issue','71000000-0000-0000-0000-000000000005','71000000-0000-0000-0000-000000000005','adjustment-probe-issue','adjustment-probe-issue-hash','{}'),
    (cmd_close,'71000000-0000-0000-0000-000000000001','71000000-0000-0000-0000-000000000002','71000000-0000-0000-0000-000000000003','transfer_close_remainder','71000000-0000-0000-0000-000000000005','71000000-0000-0000-0000-000000000005','adjustment-probe-close','adjustment-probe-close-hash','{}');
  begin insert into public.inventory_reservation_adjustments(reservation_id,transfer_allocation_id,transfer_id,command_id,adjustment_type,quantity_base,reason,created_by) values(res_b,'71000000-0000-0000-0000-000000000063','71000000-0000-0000-0000-000000000061',cmd_cancel,'manually_released',1,'bad allocation','71000000-0000-0000-0000-000000000005'); raise exception 'reservation/allocation mismatch did not fail'; exception when others then if position('allocation integrity denied' in sqlerrm)=0 then raise; end if; end;
  begin insert into public.inventory_reservation_adjustments(reservation_id,transfer_allocation_id,transfer_id,command_id,adjustment_type,quantity_base,reason,created_by) values(res_a,'71000000-0000-0000-0000-000000000063','71000000-0000-0000-0000-000000000087',cmd_cancel,'manually_released',1,'bad transfer','71000000-0000-0000-0000-000000000005'); raise exception 'reservation/transfer mismatch did not fail'; exception when others then if position('transfer integrity denied' in sqlerrm)=0 then raise; end if; end;
  begin insert into public.inventory_reservation_adjustments(reservation_id,transfer_allocation_id,transfer_id,command_id,adjustment_type,quantity_base,related_operation_id,reason,created_by) values(res_b,'71000000-0000-0000-0000-000000000064','71000000-0000-0000-0000-000000000061',cmd_issue,'issue_consumed',1,op_a,'bad operation','71000000-0000-0000-0000-000000000005'); raise exception 'mismatched operation did not fail'; exception when others then if position('issue adjustment integrity denied' in sqlerrm)=0 then raise; end if; end;
  begin insert into public.inventory_reservation_adjustments(reservation_id,transfer_allocation_id,transfer_id,command_id,adjustment_type,quantity_base,related_closure_id,reason,created_by) values(res_b,'71000000-0000-0000-0000-000000000064','71000000-0000-0000-0000-000000000061',cmd_close,'closure_released',1,close_other,'bad closure','71000000-0000-0000-0000-000000000005'); raise exception 'mismatched closure did not fail'; exception when others then if position('closure adjustment integrity denied' in sqlerrm)=0 then raise; end if; end;
  begin insert into public.inventory_reservation_adjustments(reservation_id,transfer_allocation_id,transfer_id,command_id,adjustment_type,quantity_base,reason,created_by) values(res_b,'71000000-0000-0000-0000-000000000064','71000000-0000-0000-0000-000000000061',cmd_cancel,'manually_released',4,'over adjustment','71000000-0000-0000-0000-000000000005'); raise exception 'over adjustment did not fail'; exception when others then if position('exceeds reservation quantity' in sqlerrm)=0 then raise; end if; end;
  set constraints all immediate;
end $$;
rollback to savepoint reservation_adjustment_direct_probes;

set local role authenticated;
select set_config('request.jwt.claim.role','authenticated',true),set_config('request.jwt.claim.sub','71000000-0000-0000-0000-000000000005',true);
select public.transfer_test_expect_failure($$insert into public.inventory_reservation_adjustments(reservation_id,transfer_allocation_id,transfer_id,command_id,adjustment_type,quantity_base,reason,created_by) select r.id,r.transfer_allocation_id,'71000000-0000-0000-0000-000000000061',c.id,'manually_released',1,'direct', '71000000-0000-0000-0000-000000000005' from public.inventory_reservations r cross join public.inventory_commands c where r.transfer_allocation_id='71000000-0000-0000-0000-000000000064' and c.idempotency_key='line-bound-issue-b-3-1'$$,'permission denied');
select public.transfer_test_expect_failure($$update public.inventory_reservation_adjustments set reason='direct'$$,'permission denied');
select public.transfer_test_expect_failure($$delete from public.inventory_reservation_adjustments$$,'permission denied');
reset role;
select public.transfer_test_expect_failure($$update public.inventory_reservation_adjustments set reason='trusted mutation'$$,'Posted inventory reservation records are append-only');
select public.transfer_test_expect_failure($$delete from public.inventory_reservation_adjustments$$,'Posted inventory reservation records are append-only');
select public.transfer_test_expect_failure($$update public.inventory_reservations set expires_at=expires_at+interval '1 hour'$$,'Posted inventory reservation records are append-only');
select public.transfer_test_expect_failure($$delete from public.inventory_reservations$$,'Posted inventory reservation records are append-only');
select public.transfer_test_assert(has_table_privilege('authenticated','public.inventory_reservation_adjustments','SELECT') and not has_table_privilege('authenticated','public.inventory_reservation_adjustments','INSERT, UPDATE, DELETE') and not has_function_privilege('authenticated','public.append_inventory_reservation_adjustment(uuid,uuid,uuid,uuid,public.inventory_reservation_adjustment_type,numeric,uuid,uuid,text,jsonb)'::regprocedure,'EXECUTE') and exists(select 1 from pg_trigger t where t.tgrelid='public.inventory_reservation_adjustments'::regclass and t.tgenabled<>'D' and t.tgname='inventory_reservation_adjustments_immutable') and exists(select 1 from pg_trigger t where t.tgrelid='public.inventory_reservations'::regclass and t.tgenabled<>'D' and t.tgname='inventory_reservations_immutable'),'reservation adjustment and reservation tables are append-only and client-write denied');

-- Expiry is a trusted, adjustment-backed ATP release. It must preserve the
-- immutable reservation, avoid legacy and physical accounting writes, attribute
-- command/event/audit records to the supplied authorized actor, and replay once.
insert into public.inventory_transfers(id,tenant_id,organization_id,facility_id,source_location_id,destination_root_location_id,transit_location_id,status,created_by,updated_by)
select '71000000-0000-0000-0000-000000000101',tenant_id,organization_id,facility_id,source_location_id,destination_root_location_id,transit_location_id,'reserved','71000000-0000-0000-0000-000000000005','71000000-0000-0000-0000-000000000005'
from public.inventory_transfers where id=:'transfer_id'::uuid;
