select status as status,(select requested_quantity_base from public.inventory_transfer_summary_projection where transfer_line_id='71000000-0000-0000-0000-000000000107') as requested,(select planned_quantity_base from public.inventory_transfer_summary_projection where transfer_line_id='71000000-0000-0000-0000-000000000107') as planned,(select issued_quantity_base from public.inventory_transfer_summary_projection where transfer_line_id='71000000-0000-0000-0000-000000000107') as issued,(select closed_remainder_quantity_base from public.inventory_transfer_summary_projection where transfer_line_id='71000000-0000-0000-0000-000000000107') as closed,(select unissued_quantity_base from public.inventory_transfer_summary_projection where transfer_line_id='71000000-0000-0000-0000-000000000107') as unissued,(select id from public.inventory_reservations where transfer_allocation_id='71000000-0000-0000-0000-000000000108') as reservation_id,(select public.inventory_transfer_reservation_remaining(id) from public.inventory_reservations where transfer_allocation_id='71000000-0000-0000-0000-000000000108') as remaining,(select count(*) from public.inventory_commands where requester_id='71000000-0000-0000-0000-000000000005' and idempotency_key='reservation-aggregate-over-1') as commands,(select count(*) from public.inventory_transactions where command_id in (select id from public.inventory_commands where requester_id='71000000-0000-0000-0000-000000000005' and idempotency_key='reservation-aggregate-over-1')) as transactions,(select count(*) from public.inventory_transfer_operations where transfer_id='71000000-0000-0000-0000-000000000106' and operation_type='issue') as operations,(select count(*) from public.inventory_reservation_adjustments where reservation_id=(select id from public.inventory_reservations where transfer_allocation_id='71000000-0000-0000-0000-000000000108')) as adjustments,(select count(*) from public.inventory_ledger_entries where batch_id='71000000-0000-0000-0000-000000000105') as ledger,(select coalesce(sum(quantity_base),0) from public.inventory_balance_projections where location_id='71000000-0000-0000-0000-000000000009' and batch_id='71000000-0000-0000-0000-000000000105' and recording_channel='system' and disposition='available') as source_qty,(select coalesce(sum(quantity_base),0) from public.inventory_balance_projections where location_id=(select transit_location_id from public.inventory_transfers where id='71000000-0000-0000-0000-000000000106') and batch_id='71000000-0000-0000-0000-000000000105' and recording_channel='system' and disposition='transit') as transit_qty,(select count(*) from public.inventory_events) as inventory_events,(select count(*) from public.inventory_transfer_events where transfer_id='71000000-0000-0000-0000-000000000106') as transfer_events,(select count(*) from public.audit_events where entity_type='inventory_transfer' and entity_id='71000000-0000-0000-0000-000000000106') as audit from public.inventory_transfers where id='71000000-0000-0000-0000-000000000106' \gset reservation_aggregate_before_
set local role authenticated;
