select public.transfer_test_expect_failure($$select public.issue_inventory_transfer('71000000-0000-0000-0000-000000000106','[{"transfer_allocation_id":"71000000-0000-0000-0000-000000000108","quantity_base":4},{"transfer_allocation_id":"71000000-0000-0000-0000-000000000108","quantity_base":4}]'::jsonb,'reservation-aggregate-over-1','reservation-aggregate-over-hash-0001','duplicate allocation request')$$,'Inventory transfer issue exceeds reservation remaining quantity');
