sfer_events'::int and (select count(*) from public.audit_events where entity_type='inventory_transfer' and entity_id='71000000-0000-0000-0000-000000000106')=:'reservation_aggregate_before_audit'::int and (select public.inventory_transfer_reservation_remaining(:'reservation_aggregate_before_reservation_id'::uuid))=:'reservation_aggregate_before_remaining'::numeric and (select status from public.inventory_transfers where id='71000000-0000-0000-0000-000000000106')=:'reservation_aggregate_before_status' and coalesce((select requested_quantity_base=:'reservation_aggregate_before_requested'::numeric and planned_quantity_base=:'reservation_aggregate_before_planned'::numeric and issued_quantity_base=:'reservation_aggregate_before_issued'::numeric and closed_remainder_quantity_base=:'reservation_aggregate_before_closed'::numeric and unissued_quantity_base=:'reservation_aggregate_before_unissued'::numeric from public.inventory_transfer_summary_projection where transfer_line_id='71000000-0000-0000-0000-000000000107'),false),'duplicate allocation issue is rejected before command, adjustment, transaction, event, audit, ledger, projection, summary or status effects');
