ndary posts one balanced transaction, two operations, two adjustments and zero remaining');

-- Replay remains command-owned: it must not append more issue operations or
-- reservation adjustments for the duplicate-grain boundary request.
set local role authenticated;
select set_config('request.jwt.claim.role','authenticated',true),set_config('request.jwt.claim.sub','71000000-0000-0000-0000-000000000005',true);
select public.issue_inventory_transfer('71000000-0000-0000-0000-000000000106',jsonb_build_array(jsonb_build_object('transfer_allocation_id','71000000-0000-0000-0000-000000000108','quantity_base',3),jsonb_build_object('transfer_allocation_id','71000000-0000-0000-0000-000000000108','quantity_base',3)),'reservation-aggregate-boundary-1','reservation-aggregate-boundary-hash-0001','exact reservation boundary');
reset role;
select public.transfer_test_assert((select count(*)=1 from public.inventory_commands where requester_id='71000000-0000-0000-0000-000000000005' and idempotency_key='reservation-aggregate-boundary-1' and status='posted') and (select count(*)=2 from public.inventory_transfer_operations where transfer_id='71000000-0000-0000-0000-000000000106' and operation_type='issue' and quantity_base=3) and (select count(*)=2 from public.inventory_reservation_adjustments where reservation_id=:'reservation_aggregate_before_reservation_id'::uuid and adjustment_type='issue_consumed' and quantity_base=3) and (select public.inventory_transfer_reservation_remaining(:'reservation_aggregate_before_reservation_id'::uuid)=0),'duplicate-grain issue replay creates no duplicate operations or adjustments');

-- The exception for issue grains is deliberately narrow.  Direct trusted
-- probes are isolated so only the index behavior is exercised.
savepoint inventory_transfer_operation_grain_probes;
insert into public.inventory_transfer_operations(id,transfer_id,transfer_allocation_id,command_id,transaction_id,operation_type,inventory_item_profile_id,batch_id,recording_channel,source_location_id,destination_location_id,source_disposition,destination_disposition,quantity_base,reason,created_by)
select '71000000-0000-0000-0000-000000000111','71000000-0000-0000-0000-000000000106','71000000-0000-0000-0000-000000000108',c.id,t.id,'issue','71000000-0000-0000-0000-000000000007','71000000-0000-0000-0000-000000000105','system','71000000-0000-0000-0000-000000000009',x.transit_location_id,'available','transit',1,'trusted issue grain probe','71000000-0000-0000-0000-000000000005' from public.inventory_commands c join public.inventory_transactions t on t.command_id=c.id cross join public.inventory_transfers x where c.requester_id='71000000-0000-0000-0000-000000000005' and c.idempotency_key='reservation-aggregate-boundary-1' and x.id='71000000-0000-0000-0000-000000000106';
insert into public.inventory_transfer_operations(id,transfer_id,transfer_allocation_id,command_id,transaction_id,operation_type,inventory_item_profile_id,batch_id,recording_channel,source_location_id,destination_location_id,source_disposition,destination_disposition,quantity_base,reason,created_by)
select '71000000-0000-0000-0000-000000000112','71000000-0000-0000-0000-000000000106','71000000-0000-0000-0000-000000000108',c.id,t.id,'issue','71000000-0000-0000-0000-000000000007','71000000-0000-0000-0000-000000000105','system','71000000-0000-0000-0000-000000000009',x.transit_location_id,'available','transit',1,'trusted issue grain probe','71000000-0000-0000-0000-000000000005' from public.inventory_commands c join public.inventory_transactions t on t.command_id=c.id cross join public.inventory_transfers x where c.requester_id='71000000-0000-0000-0000-000000000005' and c.idempotency_key='reservation-aggregate-boundary-1' and x.id='71000000-0000-0000-0000-000000000106';
