do $$
declare cmd uuid; tx uuid; transit uuid;
begin
  select c.id,t.id,x.transit_location_id into cmd,tx,transit from public.inventory_commands c join public.inventory_transactions t on t.command_id=c.id cross join public.inventory_transfers x where c.requester_id='71000000-0000-0000-0000-000000000005' and c.idempotency_key='reservation-aggregate-boundary-1' and x.id='71000000-0000-0000-0000-000000000106';
  insert into public.inventory_transfer_operations(transfer_id,transfer_allocation_id,command_id,transaction_id,operation_type,inventory_item_profile_id,batch_id,recording_channel,source_location_id,destination_location_id,source_disposition,destination_disposition,quantity_base,reason,created_by) values('71000000-0000-0000-0000-000000000106','71000000-0000-0000-0000-000000000108',cmd,tx,'receive','71000000-0000-0000-0000-000000000007','71000000-0000-0000-0000-000000000105','system',transit,'71000000-0000-0000-0000-000000000011','transit','available',1,'trusted receive grain probe','71000000-0000-0000-0000-000000000005');
