  insert into public.inventory_transfer_operations(transfer_id,transfer_allocation_id,command_id,transaction_id,operation_type,inventory_item_profile_id,batch_id,recording_channel,source_location_id,destination_location_id,source_disposition,destination_disposition,quantity_base,reason,created_by) values('71000000-0000-0000-0000-000000000106','71000000-0000-0000-0000-000000000108',cmd,tx,'reject','71000000-0000-0000-0000-000000000007','71000000-0000-0000-0000-000000000105','system',transit,transit,'transit','returns_hold',1,'trusted reject grain probe','71000000-0000-0000-0000-000000000005');
  begin
